import { useState } from "react";
import { Btn } from "../components/ui/Btn";
import { Icon } from "../components/ui/Icon";

const AuthPage = ({ onLogin, students, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [error, setError] = useState("");

  // ✅ Fixed Admin Credentials
  const ADMIN_EMAIL = "admin@hostelhub.com";
  const ADMIN_PASSWORD = "admin123";
  const ADMIN_USER = {
    id: "admin_001",
    name: "Admin",
    email: ADMIN_EMAIL,
    role: "admin",
    roomId: null
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setError("");

    if (isLogin) {
      // ✅ LOGIN - Check for Admin first
      if (email === ADMIN_EMAIL && password === ADMIN_PASSWORD) {
        onLogin(ADMIN_USER);
        return;
      }

      // Check for Student
      const student = students.find(s => s.email === email);
      if (student && password === "student123") { // Default password for students
        onLogin({
          id: student.id,
          name: student.name,
          email: student.email,
          role: "student",
          roomId: student.roomId,
          assignedOn: student.assignedOn
        });
      } else {
        setError("Invalid email or password. Use admin@hostelhub.com / admin123 for admin");
      }
    } else {
      // ✅ REGISTER - New Student
      if (!name || !email || !password) {
        setError("Please fill all fields");
        return;
      }

      // Check if email already exists
      if (students.some(s => s.email === email)) {
        setError("Email already registered");
        return;
      }

      const newStudent = {
        id: Date.now(),
        name,
        email,
        password, // In real app, hash this!
        role: "student",
        roomId: null,
        assignedOn: null
      };

      onRegister(newStudent);
      onLogin({
        id: newStudent.id,
        name: newStudent.name,
        email: newStudent.email,
        role: "student",
        roomId: null
      });
    }
  };

  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)"
    }}>
      <div style={{
        background: "white",
        padding: "40px",
        borderRadius: "16px",
        boxShadow: "0 20px 60px rgba(0,0,0,0.3)",
        width: "450px",
        maxWidth: "90%"
      }}>
        <div style={{ textAlign: "center", marginBottom: "32px" }}>
          <div style={{ fontSize: "48px", marginBottom: "8px" }}>🏨</div>
          <h1 style={{ fontSize: "28px", fontWeight: "bold", marginBottom: "8px" }}>HostelHub</h1>
          <p style={{ color: "#64748b" }}>
            {isLogin ? "Welcome back!" : "Create your account"}
          </p>
        </div>

        {error && (
          <div style={{
            background: "#fee2e2",
            color: "#991b1b",
            padding: "12px",
            borderRadius: "8px",
            marginBottom: "20px",
            fontSize: "14px"
          }}>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          {!isLogin && (
            <div style={{ marginBottom: "16px" }}>
              <label style={{ display: "block", marginBottom: "6px", fontWeight: "500" }}>
                Full Name
              </label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Enter your name"
                style={{
                  width: "100%",
                  padding: "12px",
                  border: "1px solid #cbd5e1",
                  borderRadius: "8px",
                  fontSize: "14px"
                }}
              />
            </div>
          )}

          <div style={{ marginBottom: "16px" }}>
            <label style={{ display: "block", marginBottom: "6px", fontWeight: "500" }}>
              Email Address
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              style={{
                width: "100%",
                padding: "12px",
                border: "1px solid #cbd5e1",
                borderRadius: "8px",
                fontSize: "14px"
              }}
            />
          </div>

          <div style={{ marginBottom: "24px" }}>
            <label style={{ display: "block", marginBottom: "6px", fontWeight: "500" }}>
              Password
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              style={{
                width: "100%",
                padding: "12px",
                border: "1px solid #cbd5e1",
                borderRadius: "8px",
                fontSize: "14px"
              }}
            />
          </div>

          <Btn
            type="submit"
            variant="primary"
            style={{
              width: "100%",
              padding: "12px",
              fontSize: "16px",
              justifyContent: "center"
            }}
          >
            {isLogin ? "Sign In" : "Register"}
          </Btn>
        </form>

        <div style={{ textAlign: "center", marginTop: "24px" }}>
          <button
            onClick={() => {
              setIsLogin(!isLogin);
              setError("");
            }}
            style={{
              background: "none",
              border: "none",
              color: "#3b82f6",
              cursor: "pointer",
              fontSize: "14px"
            }}
          >
            {isLogin ? "Don't have an account? Register" : "Already have an account? Sign In"}
          </button>
        </div>

        {/* Demo Credentials */}
        <div style={{
          marginTop: "24px",
          padding: "16px",
          background: "#f8fafc",
          borderRadius: "8px",
          fontSize: "12px"
        }}>
          <p style={{ fontWeight: "bold", marginBottom: "8px" }}>📋 Demo Credentials:</p>
          <p><strong>Admin:</strong> admin@hostelhub.com / admin123</p>
          <p><strong>Student:</strong> sharik@gmail.com / student123</p>
          <p><strong>Or Register</strong> as new student</p>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
